INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2053, 209845, 5, 74, '本命年的RAP歌', '大学毕业一年整，还是和去年一个德行。本命年很是不幸，口袋里依旧没有纹银。先是伊拉克战争，再有SARS坑人。矿难多多，还有地震。法轮功还在害人，大家都很愤恨。单位效益不好，我老在家里登。出去找个兼职不易，吃饭还是和同事两个男人。想想去年啥没学会，就是厨艺大增。想邀好友来寒舍聚聚，却总也没有心情。怀念国荣哥哥，一个人看《东邪西毒》哭个不行。我说我是西“厨”霸王，因为我住在首都北京的西直门。想想还有什么，本明年颇为不顺。刚回北京就得了眼病，前两天还高烧的不轻。本来上半年风调雨顺，家里穷亲戚能有个好的收成，洪水却又在我的本命年，淹了我的故乡人。中华民族脊梁很硬，党领导我们走出困难同甘共苦还是一家亲。期盼下半年什么都能变好，大家都能过日子舒心。就算我的本命年有很多不幸，也都是些小事缠身。亲戚朋友兄弟姐妹父母二老都在操劳，希望大家不要生病。糟透的心情，让我很是郁闷不开心。其实可能自己要求太高，心情就会老是不好。其实我还没说到重点，我的本命年不顺连累了大家，我也是没有办法。开心的事情也有很多，我来慢慢说说。哥们好友找到了好的工作，还有的考上了研究生。有的哥们结了婚，还没来得及凑礼金我的那份。据说这位哥们的媳妇已经怀了孕，看来春节又多个叫叔叔的小人儿。叔叔估计他刚出生还不会叫，见了面按照家乡风俗，喜欢小孩的我还要开开心心的掏腰包。还有件事情放在最后说，突出重点因为它让我最为开心。我说我相信爱情，所以一直在苦苦的等。世间因缘本是天注定，我小陈找到了我今生最爱的人！一年前单位卡拉OK，我唱郑均《灰姑娘》拿了第五名，我当着众多领导同事开口许了一个愿，就是下一年能找到我的心上人。我从没有因为老是单身失去信心，这转眼它就美梦成了真。女友长的很是可爱，我总也看不够心里乐开了怀。温柔贤淑持家有道唇红齿白肤滑如脂蜂腰纤细，而且知书达理很爱学习。她家门前绕着小溪，会炒茶叶还精通茶艺。本命年乐观的我看到，我和女友将来生活在一起白头偕老！', '大学毕业一年整，还是和去年一个德行。本命年很是不幸，口袋里依旧没有纹银。先是伊拉克战争，再有SARS坑人。矿难多多，还有地震。法轮功还在害人，大家都很愤恨。单位效益不好，我老在家里登。出去找个兼职不易，吃饭还是和同事两个男人。想想去年啥没学会，就是厨艺大增。想邀好友来寒舍聚聚，却总也没有心情。怀念国荣哥哥，一个人看《东邪西毒》哭个不行。我说我是西“厨”霸王，因为我住在首都北京的西直门。想想还有什么，本明年颇为不顺。刚回北京就得了眼病，前两天还高烧的不轻。本来上半年风调雨顺，家里穷亲戚能有个好的收成，洪水却又在我的本命年，淹了我的故乡人。中华民族脊梁很硬，党领导我们走出困难同甘共苦还是一家亲。期盼下半年什么都能变好，大家都能过日子舒心。就算我的本命年有很多不幸，也都是些小事缠身。亲戚朋友兄弟姐妹父母二老都在操劳，希望大家不要生病。糟透的心情，让我很是郁闷不开心。其实可能自己要求太高，心情就会老是不好。其实我还没说到重点，我的本命年不顺连累了大家，我也是没有办法。开心的事情也有很多，我来慢慢说说。哥们好友找到了好的工作，还有的考上了研究生。有的哥们结了婚，还没来得及凑礼金我的那份。据说这位哥们的媳妇已经怀了孕，看来春节又多个叫叔叔的小人儿。叔叔估计他刚出生还不会叫，见了面按照家乡风俗，喜欢小孩的我还要开开心心的掏腰包。还有件事情放在最后说，突出重点因为它让我最为开心。我说我相信爱情，所以一直在苦苦的等。世间因缘本是天注定，我小陈找到了我今生最爱的人！一年前单位卡拉OK，我唱郑均《灰姑娘》拿了第五名，我当着众多领导同事开口许了一个愿，就是下一年能找到我的心上人。我从没有因为老是单身失去信心，这转眼它就美梦成了真。女友长的很是可爱，我总也看不够心里乐开了怀。温柔贤淑持家有道唇红齿白肤滑如脂蜂腰纤细，而且知书达理很爱学习。她家门前绕着小溪，会炒茶叶还精通茶艺。本命年乐观的我看到，我和女友将来生活在一起白头偕老！', '忘记了快乐，也忘不了忧伤。过时的人儿，应该默默的躲起来……来词乱搞！', '2003-07-27 07:53:00', 4, '20030819185609_bbsid_209845_board_5_9e7cd0fac1.html', '20030819185609');
